mapper.select:
SELECT s.* FROM student s JOIN ( SELECT DISTINCT s.id FROM student s JOIN course_record cr ON s.id = cr.student_id JOIN teacher_course tc ON cr.course_id = tc.course_id LEFT JOIN parent_student ps ON s.id = ps.student_id LEFT JOIN parent p ON ps.parent_id = p.id
tc.teacher_id = #{dto.teacherId}
AND s.sex = #{dto.sex}
AND ( s.student_name LIKE CONCAT('%', #{dto.keyword}, '%') OR s.id LIKE CONCAT('%', #{dto.keyword}, '%') OR p.phone LIKE CONCAT('%', #{dto.keyword}, '%') )
) AS temp ON s.id = temp.id
ORDER BY s.update_time DESC, s.id

SELECT s.* FROM student s WHERE s.institution_id = #{dto.institutionId}
AND s.sex = #{dto.sex}
AND ( s.student_name LIKE CONCAT('%', #{dto.keyword}, '%') OR s.id LIKE CONCAT('%', #{dto.keyword}, '%') -- 改为 EXISTS 子查询，避免 JOIN 导致重复 OR EXISTS ( SELECT 1 FROM parent_student ps JOIN parent p ON ps.parent_id = p.id WHERE ps.student_id = s.id AND p.phone LIKE CONCAT('%', #{dto.keyword}, '%') ) )
ORDER BY s.update_time DESC, s.id

SELECT s.*
FROM student s
WHERE s.id = #{dto.studentId}
